const data = $input.first().json;
const windSpeed = data.current?.wind_speed_10m || 0;
const gusts = data.current?.wind_gusts_10m || 0;
const precipitation = data.current?.precipitation || 0;
const code = data.current?.weather_code || 0;
const forecastGusts = data.daily?.wind_gusts_10m_max || [];
const forecastRain = data.daily?.precipitation_sum || [];

// Beaufort scale mapping
// Storm force = Beaufort 10 (89-102 km/h), Violent storm = 11 (103-117), Hurricane = 12 (>117)
const maxForecastGusts = Math.max(...forecastGusts.map(g => g || 0));
const totalRain = forecastRain.slice(0, 2).reduce((s, v) => s + (v || 0), 0);

// Severe weather codes: 80-99 thunderstorms/hail/violent rain
const isSevereCode = code >= 80;

let severity = 'Low';
let probability = 0.05;
let action = 'monitor';

if (gusts >= 103 || maxForecastGusts >= 103 || (gusts >= 75 && isSevereCode)) {
  severity = 'Critical'; probability = 0.90; action = 'issue_storm_emergency';
} else if (gusts >= 75 || maxForecastGusts >= 89 || (totalRain >= 40 && gusts >= 50)) {
  severity = 'High'; probability = 0.70; action = 'issue_storm_warning';
} else if (gusts >= 50 || maxForecastGusts >= 62 || totalRain >= 25) {
  severity = 'Medium'; probability = 0.45; action = 'issue_storm_advisory';
} else if (gusts >= 30 || windSpeed >= 25) {
  severity = 'Low'; probability = 0.20; action = 'monitor_elevated';
}

return [{ json: {
  incidentType: 'severe_storm',
  severity,
  probability,
  windSpeedKmh: windSpeed,
  gustsKmh: gusts,
  precipitationMm: precipitation,
  weatherCode: code,
  maxForecastGusts,
  totalForecastRainMm: Math.round(totalRain * 10) / 10,
  isSevereCode,
  action,
  shouldAlert: severity !== 'Low' || action === 'monitor_elevated',
  timestamp: new Date().toISOString()
}}];
